{

  "$schema": "https://json-schema.org/draft/2020-12/schema",

  "$id": "https://github.com/Juwan-Hwang/polyglotir",
  "title": "SILP IR",

  "type": "object",

  "additionalProperties": false,

  "required": ["intent", "meta"],

  "properties": {

    "silp": {
      "type": "string",
      "pattern": "^v\\d+$",
      "default": "v1"
    },

    "version": { "type": "string", "default": "ir-v0.1" },

    "intent": { "type": "string", "pattern": "^![A-Z][A-Z_]*$" },

    "entities": {

      "type": "array",

      "items": {

        "type": "object",

        "additionalProperties": true,

        "required": ["id", "value"],

        "properties": {

          "id": { "type": "string" },

          "value": { "type": "string" },

          "action": {
          "type": "string",
          "pattern": "^![A-Z][A-Z_]*$"
        }

        }

      }

    },

    "constraints": {

      "type": "array",

      "items": {

        "type": "object",

        "additionalProperties": true,

        "required": ["type", "value"],

        "properties": {

          "type": { "type": "string" },

          "value": { "type": "string" },

          "time": { "type": "string" }

        }

      }

    },

    "alternatives": {

      "type": "array",

      "items": {

        "type": "object",

        "additionalProperties": true,

        "required": ["action"],

        "properties": {

          "action": {
          "type": "string",
          "pattern": "^![A-Z][A-Z_]*$"
        },

          "target": { "type": "string" },

          "location": { "type": "string" }

        }

      }

    },

    "meta": {

      "type": "object",

      "additionalProperties": true,

      "required": ["req_id"],

      "properties": {

        "req_id": { "type": "string", "pattern": "^[a-f0-9]{4,8}$" },

        "session_id": { "type": "string" },

        "priority": { "type": "integer", "default": 0 },

        "confidence": {
          "type": "number",
          "minimum": 0,
          "maximum": 1,
          "default": 1.0
        },

        "seq": { "type": "array", "items": { "type": "string" } },

        "out": { "type": "string", "default": "natural" },

        "next_agent": { "type": "string" }

      }

    }

  }

}

# Negation logic

if !rain(t+1): start(hike) else start(cards@indoor)

# Multi-constraint with secondary action

if loc(me,Beijing,t+1am): cancel(flight,t+1pm); email(zhangsan)

# Keyword arguments

translate(src=fr_rev_bold, tgt=shakespeare_en, style=archaic_heavy)

# Operator condition

if weather>rain: switch(indoor_activity)

# Nested constraints

if budget<=500 and rating>=4.0: book(hotel,downtown,t+5)
